const a={name:"Kinakål",icon:"kinakal",family:"Korsblommiga",familyLatin:"Brassicaceae",difficulty:"Enkel",difficultyWhy:"Tacksam och snabbväxande bara du sår vid rätt tidpunkt. Hemligheten? Så i juli och låt henne bli en höstkål - då slipper du allt strul med skottbildning.",zones:{outdoor:[1,2,3,4,5],indoor:null,greenhouse:[1,2,3,4,5,6,7]},days:"55-75",spacing:"30-40 cm",rowSpacing:"40-50 cm",depth:"1-2 cm",ph:{min:6.5,max:7.5,ideal:7},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"partial-sun",detail:"Trivs i sol men uppskattar halvskugga mitt på dagen, särskilt vid höstsådd. Lite skugga håller temperaturen nere och minskar risken att hon skjuter i blom."},temperature:{min:-3,max:25,ideal:"15-20°C",detail:"Klarar lätt frost ner till -3°C och blir faktiskt sötare av det! Men över 22-25°C i kombination med långa dagar panikblommar hon. Trivs allra bäst i sval höstluft."},wind:{level:"Skyddat",detail:"Kinakål bildar höga, lösa huvuden som kan bli vindkänsliga. Ett skyddat läge gör att huvudena sluter sig finare och bladen inte torkar ut."}},watering:{need:"Medel-Hög",icon:"water",summary:"Kinakål är till stor del vatten - hon behöver jämn fukt hela vägen från sådd till skörd. Torka stressar henne och kan trigga blomning, så var generös men undvik stående vatten.",phases:[{phase:"Groning (0-1 vecka)",need:"Hög",tip:"Håll jorden jämnt fuktig tills fröna grott. Kinakål gror snabbt, ofta inom 4-7 dagar."},{phase:"Tillväxt (1-4 veckor)",need:"Medel-Hög",tip:"Vattna regelbundet 2-3 gånger i veckan. Jämn fukt ger saftiga, milda blad och förhindrar att hon stressar."},{phase:"Huvudbildning (4-8 veckor)",need:"Hög",tip:"Kritisk period! Nu bygger hon sitt huvud och behöver ordentligt med vatten. Torka nu kan ge lösa, dåliga huvuden."},{phase:"Skörd (8-10 veckor)",need:"Medel",tip:"Fortsätt vattna men minska något. Alltför blöt jord vid skörd gör att huvudena lagras sämre."}],mistakes:["Ojämn vattning stressar plantan och triggar skottbildning - det vanligaste misstaget","Stående vatten ger rotröta, särskilt i tung lerjord","Torka under huvudbildningen ger lösa, luftiga huvuden med bitter smak","Vattna på bladen istället för vid roten ökar risken för svampsjukdomar"],tip:"Mulcha med gräsklipp eller halm runt plantorna - det håller jorden jämnt fuktig och sval, precis som kinakål vill ha det."},soil:"Mullrik, näringsrik och fukthållande jord med god dränering. Kinakål vill ha varm, kalkrik jord - hon är hungrigare än de flesta bladgrönsaker.",soilTips:["Blanda in rikligt med brunnen kompost eller stallgödsel innan sådd - kinakål är en riktig storätare","Kalka om pH ligger under 6.5 - kinakål trivs i neutral till svagt basisk jord och kalk minskar risken för klumprotsjuka","Undvik kompakt lerjord - luckra ordentligt och blanda in sand om jorden är tung"],timeline:{1:[{phase:"Förkultivering",months:"Mar-Apr",icon:"seedling"},{phase:"Utplantering vår",months:"Apr-Maj",icon:"seedling"},{phase:"Direktså höst",months:"Jun-Jul",icon:"seedling"},{phase:"Tillväxt höst",months:"Jul-Sep",icon:"leaf"},{phase:"Skörd",months:"Sep-Nov",icon:"harvest"}],4:[{phase:"Förkultivering",months:"Apr",icon:"seedling"},{phase:"Utplantering vår",months:"Maj",icon:"seedling"},{phase:"Direktså höst",months:"Jul",icon:"seedling"},{phase:"Tillväxt höst",months:"Aug-Sep",icon:"leaf"},{phase:"Skörd",months:"Sep-Okt",icon:"harvest"}],6:[{phase:"Förkultivering",months:"Maj",icon:"seedling"},{phase:"Utplantering",months:"Jun",icon:"seedling"},{phase:"Direktså höst",months:"Jun-Jul",icon:"seedling"},{phase:"Tillväxt höst",months:"Jul-Aug",icon:"leaf"},{phase:"Skörd",months:"Aug-Sep",icon:"harvest"}]},nutritionData:[{month:"Jul",N:30,P:20,K:20,label:"Sådd"},{month:"Aug",N:60,P:30,K:35,label:"Tillväxt"},{month:"Sep",N:50,P:35,K:45,label:"Huvudbildning"},{month:"Okt",N:25,P:20,K:30,label:"Skörd"}],nutritionTips:[{timing:"Före sådd/plantering",tip:"Grundgödsla med brunnen kompost och en näve benmjöl per kvadratmeter. Kinakål vill ha en näringsrik start."},{timing:"Under tidig tillväxt",tip:"Ge en omgång flytande nässelvatten eller kompostvatten efter 2-3 veckor. Det kväverika gödslat ger frodiga blad."},{timing:"Vid huvudbildning",tip:"En sista giva med kaliumrikt gödsel (vedaska eller algbaserat) stärker plantan och ger fastare huvuden."},{timing:"Hela säsongen",tip:"Övergödsla inte med kväve sent - det gör bladen vattniga och försämrar lagringen."}],companions:{good:[{id:"lok",name:"Lök",icon:"vegetable",why:"Lökens starka doft förvirrar kålflugor och andra kålskadedjur - en naturlig bodyguard"},{id:"morot",name:"Morot",icon:"vegetable",why:"Kompletterande rotsystem - moroten går djupt medan kinakål har ytliga rötter. Doften förvirrar varandras skadedjur"},{id:"dill",name:"Dill",icon:"herb",why:"Lockar nyttoinsekter som äter bladlöss, och doften kan förvirra kålfjärilar"},{id:"spenat",name:"Spenat",icon:"vegetable",why:"Bra markskydd som håller jorden fuktig och sval runt kinakålen"}],bad:[{id:"gronkal",name:"Grönkål",icon:"vegetable",why:"Samma familj - delar kålfluga, jordloppor och klumprotsjuka"},{id:"broccoli",name:"Broccoli",icon:"vegetable",why:"Samma familj - konkurrerar om samma näring och ökar sjukdomstrycket"},{id:"jordgubbar",name:"Jordgubbar",icon:"berry",why:"Lockar sniglar som älskar kinakål, och konkurrerar om fukt"}]},rotation:{avoid:[{id:"gronkal",name:"Grönkål"},{id:"broccoli",name:"Broccoli"},{id:"blomkal",name:"Blomkål"},{id:"vitkal",name:"Vitkål"},{id:"radisa",name:"Rädisa"},{id:"pak-choi",name:"Pak choi"},{id:"kalrabbi",name:"Kålrabbi"}],avoidWhy:"Alla korsblommiga delar klumprotsjuka, kålbråck och kålfluga. Vänta minst 4 år innan du odlar kinakål på samma plats som annan kål stått.",goodBefore:[{name:"Baljväxter (ärtor, bönor)"},{id:"lok",name:"Lök"},{id:"potatis",name:"Potatis"}],goodBeforeWhy:"Baljväxter fixerar kväve som kinakål älskar. Lök och potatis lämnar ren jord utan kålsjukdomar.",goodAfter:[{id:"morot",name:"Morot"},{id:"lok",name:"Lök"},{id:"sallat",name:"Sallat"}],goodAfterWhy:"Morötter, lök och sallat tillhör helt andra familjer och påverkas inte av kålsjukdomar i jorden."},varieties:[{name:"Granaat",zones:[1,2,3,4,5],note:"En av få OP-sorter som fortfarande finns. Bildar fina cylindriska huvuden med ljusgröna, krispiga blad och breda vita mittnerv. Pålitlig och beprövad. Runåbergs, ekologiskt frö."},{name:"Kaito",zones:[1,2,3,4,5],note:"Ny OP-sort med kompakta ovala huvuden, 20-25 cm höga. Ovanligt god motståndskraft mot skottbildning för att vara öppenpollinerad - äntligen! Lindbloms, ekologiskt/demeter."},{name:"Scarvita F1",zones:[1,2,3,4,5,6],note:"F1-hybrid med vackra mörkgröna blad med lila ton. Sen att skjuta i blom och tål mer värme. OBS: F1 - sparar du frö får du inte samma sort tillbaka. Nelson Garden."},{name:"Bilko F1",zones:[1,2,3,4,5,6],note:"Robust F1-hybrid som ger stora, tunga huvuden (1-2 kg). Mycket god lagringsförmåga och motståndskraftig mot sjukdomar. OBS: F1 - ger inte sortäkta frö. Semenco, ekologiskt."}],problems:[{name:"Jordloppor",symptom:"Massor av små hål i bladen, som om någon skjutit med hagelgevär. Värst i torr, varm väderlek.",fix:"Fiberduk direkt vid sådd är det enda som verkligen funkar. Håll jorden fuktig - jordloppor avskyr fukt. Blandodla med lök."},{name:"Kålfluga",symptom:"Plantan vissnar trots vattning. Tittar du vid roten hittar du vita larver som äter sig igenom.",fix:"Kålkrage runt stjälken hindrar flugan från att lägga ägg. Fiberduk fungerar också bra som barriär."},{name:"Klumprotsjuka",symptom:"Plantan blir gul, vissnar och växer dåligt. Rötterna har fula, svulstliknande knölar.",fix:"Ingen bot tyvärr. Kalka jorden till pH 7+, håll god växtföljd (minst 4 år) och kompostera aldrig sjuka plantor. Dränera bra - sjukdomen trivs i blöt jord."},{name:"Sniglar",symptom:"Stora, oregelbundna hål i bladen och slemspår. Värst på hösten i fuktig väderlek.",fix:"Snigelkorn, ölfällor eller plocka för hand på kvällen. Kinakålen är ren snigelmat - var extra vaksam på fuktiga höstkvällar."}],goodToKnow:[{icon:"warning",title:"Så ALDRIG mitt i sommaren",text:"Kinakål är extremt känslig för långa dagar och värme - hon skjuter rakt i blom. I Sverige betyder det: så i juli för höstskörd. Vårsådd med förkultivering kan fungera men kräver mer planering och rätt sortval.",severity:"warning"},{icon:"warning",title:"Känslig vid störning",text:"Kinakål ogillar att bli omflyttad och störd. Vill du förkultivera, använd torvkrukor eller djupa pluggar som du sätter ner direkt i jorden - då slipper rötterna chocken.",severity:"warning"},{icon:"harvest",title:"Sötare efter frost",text:"Precis som grönkål blir kinakål sötare och mildare efter den första lätta frosten. Plantan omvandlar stärkelse till socker som frostskydd - och det kan du smaka!",severity:"tip"},{icon:"leaf",title:"Perfekt kimchikål",text:"Kinakål är grunden i koreansk kimchi. Odla en extra omgång på hösten, salta och krydda med chili och vitlök - du får probiotisk mat som håller hela vintern.",severity:"tip"},{icon:"sun",title:"Fiberduk från dag ett",text:"Jordloppor och kålfluga attackerar direkt. En fiberduk vid sådd löser båda problemen och håller dessutom jämnare fukt och temperatur. Lyft bara för vattning och ogräsrensning.",severity:"tip"},{icon:"seedling",title:"Lagrar bättre än du tror",text:"Sena sorter som Bilko F1 kan hålla sig 2-3 månader i kylskåp. Packa varje huvud i tidningspapper och lägg i grönsakslådan - perfekt vinterförråd.",severity:"tip"}],sowing:{method:"both",label:"Direktsådd eller förkultivering",description:"Kinakål kan både direktsås och förkultiveras. Höstsådd direkt i juli är enklast och ger bäst resultat. Vårsådd kräver förkultivering inomhus och snabb utplantering innan dagarna blir för långa.",steps:["Direktsådd (rekommenderas): Så i juli, direkt på friland. Dra ett grunt spår (1-2 cm djupt) och lägg fröna med 5-10 cm mellanrum","Täck med ett tunt lager jord och vattna försiktigt med stril","Gallra till 30-40 cm avstånd när plantorna har 3-4 riktiga blad - gallringsplantorna kan ätas som babysallad","Förkultivering: Så i djupa pluggar eller torvkrukor 3-4 veckor före utplantering (mars-april beroende på zon)","Undvik att störa rötterna vid utplantering - kinakål ogillar omplantering","Plantera ut på samma djup och vattna rikligt vid planteringen","Täck med fiberduk direkt efter sådd/plantering för att skydda mot jordloppor och kålfluga"],tips:["Höstsådd i juli är det säkraste - svalare väder, kortare dagar och färre problem med skottbildning","Vårsådd kräver en sort som tål långa dagar (Kaito eller Bilko F1) och snabb utplantering","Fiberduk direkt vid sådd skyddar mot jordloppor, kålfluga och håller jämn fukt","Successiv sådd var 2 vecka i juli ger skörd under längre tid"],indoorWeeks:"3-4 veckor"},seedSaving:{difficulty:"Medel",type:"Korspollinerare",biennial:!1,description:"Kinakål kan gå i blom och sätta frö samma säsong (om hon stressas) eller övervintras för fröproduktion. Hon korsar extremt lätt med pak choi, majrova och alla andra Brassica rapa - det gör frötagning knepigt om du odlar flera arter.",steps:["Välj de finaste plantorna med bäst huvudbildning och låt dem stå kvar","I milda vintrar kan kinakål övervintra utomhus med skydd (zon 1-2)","Alternativt: stressa en höstplanta genom att minska vattning - hon börjar blomma","Gula blommor pollineras av insekter - blommorna sitter på höga stjälkar","Låt skidorna mogna på plantan tills de blir bruna och torra","Klipp av stjälkarna och torka i papperspåse inomhus en vecka","Gnugga loss fröna och blås bort skal och skräp försiktigt","Förvara torrt och svalt i märkt påse"],isolation:"Korsar med pak choi, majrova, rova och alla andra Brassica rapa. Isolera minst 500 m eller odla bara en sort ur denna grupp för frösparande.",storageYears:"3-5 år",tip:"Eftersom kinakål korsar så lätt med pak choi och majrova, bör du bara spara frö om du inte odlar andra Brassica rapa-arter i närheten. F1-hybrider (Bilko, Scarvita) ger inte sortäkta avkomma - använd Granaat eller Kaito för frötagning."},storage:{shelfLife:"1-3 månader",methods:[{method:"Kylskåp",icon:"snowflake",duration:"2-3 månader",description:"Packa hela huvudet i tidningspapper och lägg i grönsakslådan. Tvätta inte förrän du ska använda - fukt på bladen ger röta. Sena sorter håller längst.",best:!0},{method:"Kallförråd",icon:"storage",duration:"1-2 månader",description:"Förvara i mörkt utrymme vid 0-5°C och hög luftfuktighet. Kontrollera regelbundet och plocka bort yttre blad som börjar vissna.",best:!1},{method:"Fermentera (kimchi)",icon:"storage",duration:"3-6 månader",description:"Salta, krydda med chili, vitlök och ingefära och låt jäsa. Klassisk koreansk kimchi - det bästa sättet att ta vara på höstskörden!",best:!1},{method:"Frysa",icon:"snowflake",duration:"6-12 månader",description:"Blanchera i 2 minuter, kyl i isvatten, pressa ur vätska och frys i portionspåsar. Passar bra i soppor och grytor.",best:!1}],tips:["Sena sorter (Bilko F1) lagras betydligt längre än tidiga sorter","Skörda på morgonen när huvudena är kalla och fasta - det förlänger hållbarheten","Lagra aldrig kinakål tillsammans med äpplen eller tomater - etylengasen påskyndar nedbrytningen","Överskott? Gör kimchi! Det är den klassiska användningen och håller hela vintern","Yttre blad som vissnar kan plockas bort - inuti är huvudet ofta fortfarande fint"]},harvestCalc:{minPerSqm:2,maxPerSqm:5,unit:"kg"}};export{a as kinakal};
